INSERT INTO public.questions (skill_id, level, question_text, question_type, options, correct_answer, marks) VALUES
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'What does SQL stand for?', 'mcq', '[{"text":"Structured Query Language","is_correct":true},{"text":"Simple Query Language","is_correct":false},{"text":"Standard Query Logic","is_correct":false},{"text":"System Query Language","is_correct":false}]', 'Structured Query Language', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'Which command creates a new table?', 'mcq', '[{"text":"CREATE TABLE","is_correct":true},{"text":"NEW TABLE","is_correct":false},{"text":"MAKE TABLE","is_correct":false},{"text":"ADD TABLE","is_correct":false}]', 'CREATE TABLE', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'What is a primary key?', 'mcq', '[{"text":"Unique identifier for a row","is_correct":true},{"text":"First column","is_correct":false},{"text":"Table name","is_correct":false},{"text":"Database name","is_correct":false}]', 'Unique identifier for a row', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'Which normal form eliminates partial dependency?', 'mcq', '[{"text":"2NF","is_correct":true},{"text":"1NF","is_correct":false},{"text":"3NF","is_correct":false},{"text":"BCNF","is_correct":false}]', '2NF', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'What does JOIN do?', 'mcq', '[{"text":"Combines rows from tables","is_correct":true},{"text":"Deletes rows","is_correct":false},{"text":"Creates indexes","is_correct":false},{"text":"Sorts data","is_correct":false}]', 'Combines rows from tables', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'Which keyword removes duplicates?', 'mcq', '[{"text":"DISTINCT","is_correct":true},{"text":"UNIQUE","is_correct":false},{"text":"REMOVE","is_correct":false},{"text":"CLEAN","is_correct":false}]', 'DISTINCT', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'What is a foreign key?', 'mcq', '[{"text":"Reference to primary key of another table","is_correct":true},{"text":"External database key","is_correct":false},{"text":"Encrypted key","is_correct":false},{"text":"Alternate key","is_correct":false}]', 'Reference to primary key of another table', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'Which command deletes all rows quickly?', 'mcq', '[{"text":"TRUNCATE","is_correct":true},{"text":"REMOVE ALL","is_correct":false},{"text":"CLEAR","is_correct":false},{"text":"ERASE","is_correct":false}]', 'TRUNCATE', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'What is an index used for?', 'mcq', '[{"text":"Speed up queries","is_correct":true},{"text":"Add constraints","is_correct":false},{"text":"Create backups","is_correct":false},{"text":"Encrypt data","is_correct":false}]', 'Speed up queries', 1),
