('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'What is normalization?', 'mcq', '[{"text":"Reducing data redundancy","is_correct":true},{"text":"Adding more data","is_correct":false},{"text":"Creating backups","is_correct":false},{"text":"Encrypting data","is_correct":false}]', 'Reducing data redundancy', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'Which SQL clause filters grouped results?', 'mcq', '[{"text":"HAVING","is_correct":true},{"text":"WHERE","is_correct":false},{"text":"FILTER","is_correct":false},{"text":"GROUP BY","is_correct":false}]', 'HAVING', 1),
