('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'Which aggregate function counts rows?', 'mcq', '[{"text":"COUNT()","is_correct":true},{"text":"SUM()","is_correct":false},{"text":"TOTAL()","is_correct":false},{"text":"NUM()","is_correct":false}]', 'COUNT()', 1),
