('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'Which type of JOIN returns all rows from the left table?', 'mcq', '[{"text":"LEFT JOIN","is_correct":true},{"text":"RIGHT JOIN","is_correct":false},{"text":"INNER JOIN","is_correct":false},{"text":"CROSS JOIN","is_correct":false}]', 'LEFT JOIN', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'What is a stored procedure?', 'mcq', '[{"text":"Precompiled SQL code stored in the database","is_correct":true},{"text":"A table type","is_correct":false},{"text":"A view","is_correct":false},{"text":"An index","is_correct":false}]', 'Precompiled SQL code stored in the database', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'Which command modifies existing data?', 'mcq', '[{"text":"UPDATE","is_correct":true},{"text":"MODIFY","is_correct":false},{"text":"CHANGE","is_correct":false},{"text":"ALTER","is_correct":false}]', 'UPDATE', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'What is a candidate key?', 'mcq', '[{"text":"A column that can uniquely identify rows","is_correct":true},{"text":"The primary key only","is_correct":false},{"text":"A foreign key","is_correct":false},{"text":"An index","is_correct":false}]', 'A column that can uniquely identify rows', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'What does GROUP BY do?', 'mcq', '[{"text":"Groups rows with same values","is_correct":true},{"text":"Sorts data","is_correct":false},{"text":"Filters rows","is_correct":false},{"text":"Joins tables","is_correct":false}]', 'Groups rows with same values', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'What is a trigger in SQL?', 'mcq', '[{"text":"Automatic action on table events","is_correct":true},{"text":"A manual command","is_correct":false},{"text":"A type of index","is_correct":false},{"text":"A stored function","is_correct":false}]', 'Automatic action on table events', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'Which constraint ensures non-null values?', 'mcq', '[{"text":"NOT NULL","is_correct":true},{"text":"REQUIRED","is_correct":false},{"text":"MANDATORY","is_correct":false},{"text":"NON_EMPTY","is_correct":false}]', 'NOT NULL', 1),
