('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'Which command removes a table completely?', 'mcq', '[{"text":"DROP TABLE","is_correct":true},{"text":"DELETE TABLE","is_correct":false},{"text":"REMOVE TABLE","is_correct":false},{"text":"CLEAR TABLE","is_correct":false}]', 'DROP TABLE', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'What is a subquery?', 'mcq', '[{"text":"A query nested inside another query","is_correct":true},{"text":"A type of JOIN","is_correct":false},{"text":"A stored procedure","is_correct":false},{"text":"An index","is_correct":false}]', 'A query nested inside another query', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'Which isolation level prevents dirty reads?', 'mcq', '[{"text":"READ COMMITTED","is_correct":true},{"text":"READ UNCOMMITTED","is_correct":false},{"text":"SERIALIZABLE","is_correct":false},{"text":"REPEATABLE READ","is_correct":false}]', 'READ COMMITTED', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'What is a composite key?', 'mcq', '[{"text":"A key made of multiple columns","is_correct":true},{"text":"A single-column key","is_correct":false},{"text":"An auto-increment key","is_correct":false},{"text":"A foreign key","is_correct":false}]', 'A key made of multiple columns', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'Which function returns the average value?', 'mcq', '[{"text":"AVG()","is_correct":true},{"text":"MEAN()","is_correct":false},{"text":"AVERAGE()","is_correct":false},{"text":"MID()","is_correct":false}]', 'AVG()', 1),
