('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'Which command adds a new column to a table?', 'mcq', '[{"text":"ALTER TABLE ADD","is_correct":true},{"text":"MODIFY TABLE ADD","is_correct":false},{"text":"UPDATE TABLE ADD","is_correct":false},{"text":"INSERT COLUMN","is_correct":false}]', 'ALTER TABLE ADD', 1),
('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'What is referential integrity?', 'mcq', '[{"text":"Ensuring foreign key references valid primary keys","is_correct":true},{"text":"Data encryption","is_correct":false},{"text":"Index optimization","is_correct":false},{"text":"Query caching","is_correct":false}]', 'Ensuring foreign key references valid primary keys', 1),
