('8c871f7c-8bdf-4955-91a7-88ac54143589', 1, 'What is a transaction?', 'mcq', '[{"text":"A unit of work that is atomic","is_correct":true},{"text":"A single SQL statement","is_correct":false},{"text":"A table operation","is_correct":false},{"text":"A database backup","is_correct":false}]', 'A unit of work that is atomic', 1),
